package main

import (
	"html"
	"io"
	"net/http"
	"net/url"
	"regexp"
	"time"

	"github.com/labstack/echo/v4"
	"github.com/labstack/echo/v4/middleware"
)

// Request represents the JSON payload for the URL preview.
type Request struct {
	URL string `json:"url"`
}

// Response represents the JSON payload returned to the client.
type Response struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles POST requests to /preview.
// It fetches the URL, extracts the <title> and meta description, and returns them as JSON.
func FetchURLPreview(ctx echo.Context) error {
	var req Request
	if err := ctx.Bind(&req); err != nil {
		return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
	}

	if req.URL == "" {
		return echo.NewHTTPError(http.StatusBadRequest, "url is required")
	}

	// Add scheme if missing
	u, err := url.Parse(req.URL)
	if err != nil || u.Scheme == "" {
		req.URL = "http://" + req.URL
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return echo.NewHTTPError(http.StatusBadGateway, "failed to fetch URL: "+err.Error())
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return echo.NewHTTPError(http.StatusBadGateway, "non-200 response")
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return echo.NewHTTPError(http.StatusInternalServerError, "failed to read response body")
	}

	htmlContent := string(body)

	title := extractTitle(htmlContent)
	description := extractMetaDescription(htmlContent)

	return ctx.JSON(http.StatusOK, Response{
		Title:       title,
		Description: description,
	})
}

// extractTitle tries to find the <title> tag in the HTML.
func extractTitle(htmlContent string) string {
	re := regexp.MustCompile(`(?i)<title>([^<]+)</title>`)
	match := re.FindStringSubmatch(htmlContent)
	if len(match) > 1 {
		return html.UnescapeString(match[1])
	}
	return ""
}

// extractMetaDescription tries to find the meta description tag in the HTML.
func extractMetaDescription(htmlContent string) string {
	// <meta name="description" content="...">
	re1 := regexp.MustCompile(`(?i)<meta\s+name=["']description["']\s+content=["']([^"']+)["']`)
	match := re1.FindStringSubmatch(htmlContent)
	if len(match) > 1 {
		return html.UnescapeString(match[1])
	}

	// <meta content="..." name="description">
	re2 := regexp.MustCompile(`(?i)<meta\s+content=["']([^"']+)["']\s+name=["']description["']`)
	match = re2.FindStringSubmatch(htmlContent)
	if len(match) > 1 {
		return html.UnescapeString(match[1])
	}

	return ""
}

