package main

import (
	"fmt"
	"io"
	"net/http"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"github.com/PuerkitoBio/goquery"
)

type previewRequest struct {
	URL string `json:"url"`
}

// httpClient with 3 second timeout
var httpClient = &http.Client{
	Timeout: 3 * time.Second,
}

// FetchURLPreview handles POST /preview requests
func FetchURLPreview(ctx echo.Context) error {
	var req previewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": err.Error()})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url is required"})
	}

	// Add scheme if missing
	if !strings.HasPrefix(req.URL, "http://") && !strings.HasPrefix(req.URL, "https://") {
		req.URL = "https://" + req.URL
	}

	resp, err := httpClient.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": fmt.Sprintf("received status code %d", resp.StatusCode),
		})
	}

	// Read the response body for parsing
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": err.Error()})
	}

	// Parse HTML
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(body)))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": err.Error()})
	}

	// Extract <title>
	title := doc.Find("title").First().Text()

	// Extract meta description (name="description")
	var description string
	doc.Find("meta").Each(func(_ int, s *goquery.Selection) {
		name, _ := s.Attr("name")
		if name == "description" {
			if content, ok := s.Attr("content"); ok {
				description = content
			}
		}
	})

	// Return JSON response
	return ctx.JSON(http.StatusOK, map[string]string{
		"title":       title,
		"description": description,
	})
}

func main() {
	e := echo.New()
	e.HideBanner = true

	// Register the handler under /preview
	e.POST("/preview", FetchURLPreview)

	// Start the server on port 8080
	if err := e.Start(":8080"); err != nil {
		fmt.Println("Server error:", err)
	}
}

