	"io"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"github.com/labstack/echo/v4/middleware"
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Fetch the URL
	client := &http.Client{Timeout: 3 * time.Second}
	resp, err := client.Do(&http.Request{
		Method: http.MethodGet,
		URL:    parsedURL,
		Header: map[string][]string{
			"User-Agent": {"Mozilla/5.0 (compatible; URLPreviewBot/1.0)"},
		},
	})
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(string(body))

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent string) (string, string) {
	title := ""
	description := ""

	// Convert to lowercase for case-insensitive matching
	lowerContent := strings.ToLower(htmlContent)

	// Extract title from <title> tag
	titleStart := strings.Index(lowerContent, "<title>")
	if titleStart == -1 {
		titleStart = strings.Index(lowerContent, "<title ")
	}
	if titleStart != -1 {
		tagEnd := strings.Index(lowerContent[titleStart:], ">")
		if tagEnd != -1 {
			contentStart := titleStart + tagEnd + 1
			titleEnd := strings.Index(lowerContent[contentStart:], "</title>")
			if titleEnd != -1 {
				title = strings.TrimSpace(htmlContent[contentStart : contentStart+titleEnd])
			}
		}
	}

	// Extract description from <meta name="description"> or <meta name="DESCRIPTION">
	descStart := strings.Index(lowerContent, `name="description"`)
	if descStart == -1 {
		descStart = strings.Index(lowerContent, `name='description'`)
	}
	if descStart != -1 {
		// Look for content attribute after the name attribute
		searchArea := lowerContent[descStart:min(descStart+200, len(lowerContent))]
		contentIdx := strings.Index(searchArea, "content=")
		if contentIdx != -1 {
			contentStart := contentIdx + 8 // len("content=")
			var contentEnd int
			if searchArea[contentStart] == '"' {
				contentStart++
				contentEnd = strings.Index(searchArea[contentStart:], "\"")
			} else if searchArea[contentStart] == '\'' {
				contentStart++
				contentEnd = strings.Index(searchArea[contentStart:], "'")
			} else {
				contentEnd = strings.IndexAny(searchArea[contentStart:], " >\t\n")
			}
			if contentEnd != -1 {
				actualStart := descStart + contentIdx + contentStart
				description = strings.TrimSpace(htmlContent[actualStart : actualStart+contentEnd])
			}
		}
	}

	return title, description
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

func main() {
	e := echo.New()
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	e.POST("/preview", FetchURLPreview)

	e.Logger.Fatal(e.Start(":1323"))
}

