// isPrivateURL checks if the URL points to a private/internal network
// This prevents SSRF attacks
func isPrivateURL(parsedURL *url.URL) bool {
	host := parsedURL.Hostname()

	// Check if it's localhost or loopback
	if host == "localhost" || host == "127.0.0.1" || host == "::1" || host == "0.0.0.0" {
		return true
	}

	// Check if the hostname resolves to a private IP
	ips, err := net.LookupIP(host)
	if err == nil {
		for _, ip := range ips {
			if ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsUnspecified() {
				return true
			}
		}
	}

	// Check for internal hostnames
	if strings.HasSuffix(host, ".localhost") || strings.HasSuffix(host, ".local") {
		return true
	}

	return false
}

// fetchWithRedirectLimit creates a client that limits redirects to prevent SSRF
// through redirect exploitation
func fetchWithRedirectLimit() *http.Client {
	return &http.Client{
		Timeout: 10 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Limit redirects to 5 to prevent redirect loops
			if len(via) >= 5 {
				return fmt.Errorf("too many redirects")
			}
			return nil
		},
	}
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// SSRF Protection: Check if URL points to internal/private network
	if isPrivateURL(parsedURL) {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Cannot access internal/private URLs"})
	}

	// Fetch the URL with limited redirects
	client := fetchWithRedirectLimit()
	httpReq, err := http.NewRequest(http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	// Limit response body to 2MB to prevent memory exhaustion
	// Using LimitedReader with a TeeReader to still be able to parse
	limitedBody := &io.LimitedReader{
		R: resp.Body,
		N: 2 * 1024 * 1024, // 2MB limit
	}

	// Parse HTML
	doc, err := goquery.NewDocumentFromReader(limitedBody)
	if err != nil {
		return ctx.JSON(http.StatusOK, PreviewResponse{
			Title:       "",
			Description: "",
		})
	}

	// Extract title
	title := doc.Find("title").First().Text()
	// Also try og:title as fallback
	if title == "" {
		title, _ = doc.Find("meta[property=\"og:title\"]").Attr("content")
	}

	// Extract description - try meta description first, then og:description
	description, _ := doc.Find("meta[name=\"description\"]").Attr("content")
	if description == "" {
		description, _ = doc.Find("meta[property=\"og:description\"]").Attr("content")
	}

	// Trim and limit lengths
	title = strings.TrimSpace(title)
	description = strings.TrimSpace(description)

	// Limit title to 200 chars
	if len(title) > 200 {
		title = title[:200]
	}

	// Limit description to 500 chars
	if len(description) > 500 {
		description = description[:500]
	}

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

