// PreviewRequest represents the JSON payload of the POST request.
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse is the JSON structure returned to the client.
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST /preview requests.
// It extracts the URL from the JSON body, fetches the page,
// and returns the title and meta description.
func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{Error: "invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{Error: "url is required"})
	}

	// Create an HTTP client with a 3‑second timeout.
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{Error: "failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{Error: "non‑200 response"})
	}

	// Read the response body.
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{Error: "failed to read response body"})
	}
	html := string(body)

	// Extract <title> content.
	titleRe := regexp.MustCompile(`(?i)<title>([^<]+)</title>`)
	titleMatch := titleRe.FindStringSubmatch(html)
	title := ""
	if len(titleMatch) > 1 {
		title = titleMatch[1]
	}

	// Extract meta description (two common attribute orders).
	descRe := regexp.MustCompile(`(?i)<meta[^>]*name=["']description["'][^>]*content=["']([^"']+)["']`)
	descMatch := descRe.FindStringSubmatch(html)

	descRe2 := regexp.MustCompile(`(?i)<meta[^>]*content=["']([^"']+)["'][^>]*name=["']description["']`)
	descMatch2 := descRe2.FindStringSubmatch(html)

	description := ""
	if len(descMatch) > 1 {
		description = descMatch[1]
	} else if len(descMatch2) > 1 {
		description = descMatch2[1]
	}

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func main() {
	e := echo.New()
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Register the handler under /preview.
