package main

import (
	"encoding/json"
	"io"
	"net/http"
	"net/url"
	"regexp"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
)

// Request body for the preview endpoint
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body for the preview endpoint
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles POST /preview
func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
	}

	// Validate that URL is provided
	if req.URL == "" {
		return echo.NewHTTPError(http.StatusBadRequest, "url is required")
	}

	// Validate URL format
	parsedURL, err := url.Parse(req.URL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return echo.NewHTTPError(http.StatusBadRequest, "invalid URL format")
	}

	// Create HTTP client with a 3‑second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return echo.NewHTTPError(http.StatusInternalServerError, "failed to fetch URL: "+err.Error())
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return echo.NewHTTPError(http.StatusInternalServerError, "non‑OK HTTP status: "+resp.Status)
	}

	// Read the response body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return echo.NewHTTPError(http.StatusInternalServerError, "failed to read response body")
	}

	html := string(body)

	// Extract <title>
	title := extractTitle(html)

	// Extract meta description (og:description or name="description")
	description := extractMetaDescription(html)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitle returns the text inside the <title> tag
func extractTitle(html string) string {
	re := regexp.MustCompile(`(?i)<title>([^<]+)</title>`)
	matches := re.FindStringSubmatch(html)
	if len(matches) > 1 {
		return strings.TrimSpace(matches[1])
	}
	return ""
}

// extractMetaDescription looks for og:description first, then name="description"
func extractMetaDescription(html string) string {
	// og:description
	reOg := regexp.MustCompile(`(?i)<meta\s+property=["']og:description["']\s+content=["']([^"']+)["']`)
	if matches := reOg.FindStringSubmatch(html); len(matches) > 1 {
		return strings.TrimSpace(matches[1])
	}

	// name="description"
	reDesc := regexp.MustCompile(`(?i)<meta\s+name=["']description["']\s+content=["']([^"']+)["']`)
	if matches := reDesc.FindStringSubmatch(html); len(matches) > 1 {
		return strings.TrimSpace(matches[1])
	}

	return ""
}

func main() {
	e := echo.New()

	// Register the preview handler
	e.POST("/preview", FetchURLPreview)

	// Start the server (listen on port 1323)
	e.Logger.Fatal(e.Start(":1323"))
}

