func FetchURLPreview(ctx echo.Context) error {
	var req Request
	if err := ctx.Bind(&req); err != nil {
		return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
	}

	if req.URL == "" {
		return echo.NewHTTPError(http.StatusBadRequest, "url is required")
	}

	// Validate URL format.
	if _, err := url.Parse(req.URL); err != nil {
		return echo.NewHTTPError(http.StatusBadRequest, "invalid URL")
	}

	// Create an HTTP client with a 3‑second timeout.
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return echo.NewHTTPError(http.StatusInternalServerError, "failed to fetch URL")
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return echo.NewHTTPError(http.StatusInternalServerError, "non‑200 response")
	}

	// Limit the response body to 2 MiB to avoid consuming too much memory.
	body, err := io.ReadAll(io.LimitReader(resp.Body, 2<<20))
	if err != nil {
		return echo.NewHTTPError(http.StatusInternalServerError, "failed to read response body")
	}

	// Extract title and meta description from the HTML.
	title, description, err := extractMeta(bytes.NewReader(body))
	if err != nil {
		return echo.NewHTTPError(http.StatusInternalServerError, "failed to parse HTML")
	}

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractMeta walks the HTML parse tree and returns the page title
// and the content of the meta description tag (or og:description fallback).
func extractMeta(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var walk func(*html.Node)
	walk = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				// Collect all text nodes inside <title>.
				var buf bytes.Buffer
				for c := n.FirstChild; c != nil; c = c.NextSibling {
					if c.Type == html.TextNode {
						buf.WriteString(c.Data)
					}
				}
				title = buf.String()
			case "meta":
				var name, prop, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
