package main

import (
	"io"
	"net/http"
	"regexp"
	"time"

	"github.com/labstack/echo/v4"
	"github.com/labstack/echo/v4/middleware"
)

// Request body structure
type URLRequest struct {
	URL string `json:"url"`
}

// Response structure
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests to /preview.
// It extracts the URL from the JSON body, fetches the page,
// and returns the page title and meta description.
func FetchURLPreview(ctx echo.Context) error {
	var req URLRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{Error: "invalid request body"})
	}
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{Error: "url is required"})
	}

	// Create an HTTP client with a 3‑second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{Error: err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{Error: "non‑200 status: " + resp.Status})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{Error: err.Error()})
	}

	html := string(body)

	// Extract title and meta description from the HTML
	title := extractTitle(html)
	description := extractMetaDescription(html)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitle returns the content of the <title> tag (case‑insensitive).
func extractTitle(html string) string {
	re := regexp.MustCompile(`(?i)<title>([^<]+)</title>`)
	matches := re.FindStringSubmatch(html)
	if len(matches) > 1 {
		return matches[1]
	}
	return ""
}

// extractMetaDescription returns the content of the meta description tag.
// It handles both <meta name="description" content="..."> and
// <meta content="..." name="description">.
func extractMetaDescription(html string) string {
	// Two patterns to cover different attribute ordering
	re := regexp.MustCompile(`(?i)<meta[^>]+name=["']description["'][^>]+content=["']([^"']+)["']|<meta[^>]+content=["']([^"']+)["'][^>]+name=["']description["']`)
	matches := re.FindStringSubmatch(html)
	// matches[1] – name before content
	// matches[2] – content before name
	if len(matches) > 1 && matches[1] != "" {
		return matches[1]
	}
	if len(matches) > 2 && matches[2] != "" {
		return matches[2]
	}
	return ""
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Register the preview endpoint
	e.POST("/preview", FetchURLPreview)

	// Start the server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

