// FetchURLPreview handles POST requests to /preview.
// It extracts the page title and meta description from the given URL.
func FetchURLPreview(ctx echo.Context) error {
	var req URLRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
	}

	// Validate the URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid URL"})
	}

	// Create an HTTP client with a 3‑second timeout.
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Perform the GET request.
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	// Read the response body.
	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "failed to read response body"})
	}

	html := string(body)

	// Extract the page title.
	title := extractTitle(html)
	// Extract the meta description.
	description := extractMetaDescription(html)

	result := PreviewResponse{
		Title:       title,
		Description: description,
		URL:         req.URL,
	}

	return ctx.JSON(http.StatusOK, result)
}

// extractTitle returns the text inside the <title> tag.
func extractTitle(html string) string {
	re := regexp.MustCompile(`(?i)<title[^>]*>(?s:(.*?))</title>`)
	matches := re.FindStringSubmatch(html)
	if len(matches) > 1 {
		return matches[1]
	}
	return ""
}

