	title := extractTitle(html)

	// Extract meta description
	description := extractDescription(html)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitle extracts the <title> tag content from HTML
func extractTitle(html string) string {
	re := regexp.MustCompile(`(?i)<title>([^<]+)</title>`)
	matches := re.FindStringSubmatch(html)
	if len(matches) > 1 {
		return matches[1]
	}
	return ""
}

// extractDescription extracts the content of <meta name="description"> or <meta property="description">
func extractDescription(html string) string {
	// Match meta name="description" or property="description"
	re := regexp.MustCompile(`(?i)<meta\s+(?:name|property)=["']description["']\s+content=["']([^"']*)["']`)
