	re2 := regexp.MustCompile(`(?i)<meta\s+content=["']([^"']*)["']\s+(?:name|property)=["']description["']`)
	matches2 := re2.FindStringSubmatch(html)
	if len(matches2) > 1 {
		return matches2[1]
	}
	return ""
}

