	// Create Echo instance
	e := echo.New()

	// Use middleware (optional)
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Register routes
	e.POST("/preview", FetchURLPreview)

	// Start server
	// For demonstration, listen on :8080
	e.Logger.Fatal(e.Start(":8080"))
}

