// FetchURLPreview handles POST /preview
func FetchURLPreview(ctx echo.Context) error {
	var req Request
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, Response{Error: "invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, Response{Error: "url is required"})
	}

	// Ensure URL has a scheme
	if !strings.HasPrefix(req.URL, "http://") && !strings.HasPrefix(req.URL, "https://") {
		req.URL = "https://" + req.URL
	}

	// HTTP client with a 3‑second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, Response{Error: fmt.Sprintf("failed to fetch URL: %v", err)})
	}
	defer resp.Body.Close()

	// Limit response size to 2 MiB to prevent excessive memory usage
	limitedBody := io.LimitReader(resp.Body, 2<<20)

	// Parse HTML
	doc, err := html.Parse(limitedBody)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, Response{Error: fmt.Sprintf("failed to parse HTML: %v", err)})
	}

	title, description := extractMeta(doc)

	return ctx.JSON(http.StatusOK, Response{
		URL:         req.URL,
		Title:       title,
		Description: description,
	})
}

// extractMeta walks the HTML node tree to extract the page title
// and the meta description (name="description" or property="og:description").
func extractMeta(n *html.Node) (title, description string) {
	var walk func(*html.Node)
	walk = func(node *html.Node) {
		if title != "" && description != "" {
			return
		}
		if node.Type == html.ElementNode {
			// <title>
			if node.Data == "title" && node.FirstChild != nil {
				title = html.UnescapeString(strings.TrimSpace(node.FirstChild.Data))
			}
			// <meta>
			if node.Data == "meta" {
				var name, prop, content string
				for _, attr := range node.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "property":
						prop = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if (name == "description" || prop == "og:description") && content != "" {
					description = html.UnescapeString(strings.TrimSpace(content))
				}
			}
		}
		for child := node.FirstChild; child != nil; child = child.NextSibling {
			walk(child)
		}
	}
	walk(n)
	return title, description
}

