func extractTitleAndDescription(htmlContent []byte) (string, string) {
	title := ""
	description := ""

	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var findMeta func(n *html.Node)
	findMeta = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Find title
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Find meta description
			if n.Data == "meta" {
				var name, content string
				var hasName, hasProp bool
				for _, attr := range n.Attr {
					if attr.Key == "name" && (attr.Val == "description" || attr.Val == "Description") {
						hasName = true
					}
					if attr.Key == "property" && attr.Val == "og:description" {
						hasProp = true
					}
					if attr.Key == "name" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}

				// Prefer og:description, fall back to meta description
				if hasName && name == "description" {
					description = content
				}
				if hasProp {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			findMeta(c)
		}
	}

	findMeta(doc)

	return title, description
}

