// parseHTML extracts the <title> content and the meta description
// (name="description" or property="og:description").
func parseHTML(r io.Reader) (title, description string) {
	tokenizer := html.NewTokenizer(r)
	for {
		tt := tokenizer.Next()
		if tt == html.ErrorToken {
			break
		}
		if tt == html.StartTagToken || tt == html.SelfClosingTagToken {
			tok := tokenizer.Token()
			if tok.Data == "title" {
				// The next token should be the text inside <title>
				if tokenizer.Next() == html.TextToken {
					title = tokenizer.Token().Data
				}
			}
			if tok.Data == "meta" {
				var name, prop, content string
				for _, attr := range tok.Attr {
					switch attr.Key {
					case "name":
						name = strings.ToLower(attr.Val)
					case "property":
						prop = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					}
				}
				if name == "description" || prop == "og:description" {
					description = content
				}
			}
		}
	}
	return
}

