import (
	"encoding/json"
	"io"
	"net/http"
	"regexp"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"github.com/labstack/echo/v4/middleware"
)

// PreviewRequest represents the JSON body of the incoming request.
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the JSON response returned to the client.
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST /preview requests.
// It extracts the URL from the JSON body, fetches the page, parses the HTML
// for the <title> and <meta name="description"> tags, and returns them as JSON.
func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{Error: "invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, PreviewResponse{Error: "URL is required"})
	}

	// Create an HTTP client with a 3‑second timeout for the request.
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{Error: "failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{Error: "received non‑200 status code"})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, PreviewResponse{Error: "failed to read response body"})
	}

	title, description := parseHTML(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTML extracts the <title> and meta description from an HTML document.
func parseHTML(data []byte) (title, description string) {
	// ---- Extract <title> ----
	reTitle := regexp.MustCompile(`(?i)<title>([^<]+)</title>`)
	if m := reTitle.FindSubmatch(data); len(m) > 1 {
		title = string(m[1])
	}

	// ---- Extract <meta name="description"> or <meta property="description"> ----
	// Find all <meta ...> tags.
	reMeta := regexp.MustCompile(`(?i)<meta[^>]+>`)
	matches := reMeta.FindAllString(string(data), -1)

	for _, tag := range matches {
		// Check if this tag describes a description.
		if strings.Contains(tag, `name="description"`) ||
			strings.Contains(tag, `name='description'`) ||
			strings.Contains(tag, `property="description"`) ||
			strings.Contains(tag, `property='description'`) {

			// Extract the content attribute value.
			reContent := regexp.MustCompile(`(?i)content=["']([^"']+)"`)
			if cm := reContent.FindStringSubmatch(tag); len(cm) > 1 {
				description = cm[1]
				break // we only need the first one
			}
		}
	}

	return title, description
}

func main() {
	// Create a new Echo instance.
	e := echo.New()

	// Add middleware (logging and recovery).
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Register the preview endpoint.
	e.POST("/preview", FetchURLPreview)

	// Start the HTTP server on port 8080.
	e.Logger.Fatal(e.Start(":8080"))
