package main

import (
	"io"
	"net/http"
	"regexp"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"github.com/labstack/echo/v4/middleware"
)

// Request represents the JSON payload
type Request struct {
	URL string `json:"url"`
}

// Response represents the JSON response
type Response struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func main() {
	// Setup Echo
	e := echo.New()
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Register handler
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Start(":8080")
}

// FetchURLPreview handles POST /preview
func FetchURLPreview(ctx echo.Context) error {
	var req Request
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url is required"})
	}

	// Ensure URL has scheme
	url := req.URL
	if !strings.HasPrefix(url, "http://") && !strings.HasPrefix(url, "https://") {
		url = "http://" + url
	}

	// Create HTTP client with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(url)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "non-200 response from URL"})
	}

	// Read response body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to read response body"})
	}

	html := string(body)

	// Extract title and description
	title, description := parseHTML(html)

	return ctx.JSON(http.StatusOK, Response{
		Title:       title,
		Description: description,
	})
}

// parseHTML extracts the <title> and <meta name="description"> from HTML
func parseHTML(html string) (title, description string) {
	// Extract title
	titleRe := regexp.MustCompile(`(?i)<title[^>]*>([^<]+)</title>`)
	m := titleRe.FindStringSubmatch(html)
	if len(m) > 1 {
		title = strings.TrimSpace(m[1])
	}

	// Extract description - two possible orderings of attributes
	descRe1 := regexp.MustCompile(`(?i)<meta[^>]+name=["']description["'][^>]+content=["']([^"']+)["']`)
	descRe2 := regexp.MustCompile(`(?i)<meta[^>]+content=["']([^"']+)["'][^>]+name=["']description["']`)

	m = descRe1.FindStringSubmatch(html)
	if len(m) > 1 {
		description = strings.TrimSpace(m[1])
	} else {
		m = descRe2.FindStringSubmatch(html)
		if len(m) > 1 {
			description = strings.TrimSpace(m[1])
		}
	}

	return
}

