// URLRequest represents the JSON request body for fetching URL preview.
type URLRequest struct {
	URL string `json:"url"`
}

// FetchURLPreview handles POST /preview requests. It extracts the 'url' from the
// request body, fetches the page, parses the HTML title and meta description,
// and returns them in a JSON response.
func FetchURLPreview(ctx echo.Context) error {
	var req URLRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
	}

	targetURL := req.URL
	if targetURL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url is required"})
	}

	// Ensure the URL has a scheme; if not, prepend http://
	if !strings.HasPrefix(targetURL, "http://") && !strings.HasPrefix(targetURL, "https://") {
		targetURL = "http://" + targetURL
	}

	// Create an HTTP client with a 3-second timeout for the request
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(targetURL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "received non-200 status"})
	}

	// Read the response body (limit to 1 MB to avoid huge allocations)
	body, err := io.ReadAll(io.LimitReader(resp.Body, 1<<20))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to read response body"})
	}

	htmlContent := string(body)

	// Extract page title and meta description from the HTML
	title := extractTitle(htmlContent)
	description := extractDescription(htmlContent)

	return ctx.JSON(http.StatusOK, map[string]string{
		"title":       title,
		"description": description,
	})
}

// extractTitle returns the text content of the <title> tag in the HTML.
func extractTitle(html string) string {
	re := regexp.MustCompile(`(?i)<title[^>]*>([^<]+)</title>`)
	matches := re.FindStringSubmatch(html)
	if len(matches) > 1 {
		return strings.TrimSpace(matches[1])
	}
	return ""
}

// extractDescription returns the content of the meta description tag (name="description"
// or property="og:description") if present.
func extractDescription(html string) string {
	// <meta name="description" content="...">
	re := regexp.MustCompile(`(?i)<meta[^>]+name=["']description["'][^>]+content=["']([^"']*)["']`)
	if m := re.FindStringSubmatch(html); len(m) > 1 && m[1] != "" {
		return strings.TrimSpace(m[1])
	}

	// <meta content="..." name="description">
	re = regexp.MustCompile(`(?i)<meta[^>]+content=["']([^"']*)["'][^>]+name=["']description["']`)
	if m := re.FindStringSubmatch(html); len(m) > 1 && m[1] != "" {
		return strings.TrimSpace(m[1])
	}

	// <meta property="og:description" content="...">
	re = regexp.MustCompile(`(?i)<meta[^>]+property=["']og:description["'][^>]+content=["']([^"']*)["']`)
	if m := re.FindStringSubmatch(html); len(m) > 1 && m[1] != "" {
		return strings.TrimSpace(m[1])
	}

	// <meta content="..." property="og:description">
	re = regexp.MustCompile(`(?i)<meta[^>]+content=["']([^"']*)["'][^>]+property=["']og:description["']`)
	if m := re.FindStringSubmatch(html); len(m) > 1 && m[1] != "" {
		return strings.TrimSpace(m[1])
	}

	return ""
}

func main() {
