// FetchURLPreview handles POST /preview
func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Validate and parse URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// Only allow http and https schemes
	scheme := strings.ToLower(parsedURL.Scheme)
	if scheme != "http" && scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Extract host (strip port if present)
	host := parsedURL.Host
	if host != "" {
		if h, _, err := net.SplitHostPort(host); err == nil {
			host = h
		}
	}

	// Resolve host to IP addresses and block private/internal IPs (SSRF protection)
	if host != "" {
		ips, err := net.LookupIP(host)
		if err != nil || len(ips) == 0 {
			return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Unable to resolve host"})
		}
		for _, ip := range ips {
			if isPrivateIP(ip) {
				return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Requests to private/internal IPs are not allowed"})
			}
		}
	}

	// Create HTTP client with timeout and without automatic redirect handling
	client := &http.Client{
		Timeout: 5 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Block redirects to avoid SSRF via open redirects
			return http.ErrUseLastResponse
		},
	}

	// Build request with context (propagate the incoming context for cancellation)
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Perform the HTTP request
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Only accept HTTP 200
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": fmt.Sprintf("Remote server returned status %d", resp.StatusCode)})
	}

	// Limit response size to 2 MB to prevent memory exhaustion
	const maxBodySize = 2 << 20 // 2 MB
	limitedReader := io.LimitReader(resp.Body, maxBodySize)

	body, err := io.ReadAll(limitedReader)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	// Optionally verify Content-Type is HTML
	contentType := strings.ToLower(resp.Header.Get("Content-Type"))
	if !strings.Contains(contentType, "text/html") {
		// Not HTML – we continue anyway but could also return empty fields
	}

	// Extract title and description from the HTML
	title, description := extractTitleAndDescription(body)

	// Truncate fields to a safe maximum length (optional)
	const maxFieldLen = 500
	if len(title) > maxFieldLen {
		title = title[:maxFieldLen]
	}
	if len(description) > maxFieldLen {
		description = description[:maxFieldLen]
	}

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// isPrivateIP checks if an IP address is private, loopback, or link‑local.
// This helps mitigate Server‑Side Request Forgery (SSRF) attacks.
func isPrivateIP(ip net.IP) bool {
	// Loopback (127.x.x.x, ::1)
	if ip.IsLoopback() {
		return true
	}

	// IPv4 private ranges
	if ip4 := ip.To4(); ip4 != nil {
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		// 169.254.0.0/16 (link‑local)
		if ip4[0] == 169 && ip4[1] == 254 {
			return true
		}
	}

	// IPv6 private (fc00::/7) and link‑local (fe80::/10)
	if ip6 := ip.To16(); ip6 != nil {
		if ip6[0] == 0xfc {
			return true
		}
		if ip6[0] == 0xfe && ip6[1]&0xc0 == 0x80 {
			return true
		}
	}

	return false
}

// extractTitleAndDescription parses HTML and extracts the <title> tag
// and the meta description (name="description" or property="og:description").
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	if len(htmlContent) == 0 {
		return "", ""
	}

	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title, description string

	var walk func(*html.Node)
	walk = func(n *html.Node) {
		// Extract <title>
		if n.Type == html.ElementNode && n.Data == "title" {
			if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
				title = strings.TrimSpace(n.FirstChild.Data)
			}
		}

		// Extract <meta name="description"> or <meta property="og:description">
		if n.Type == html.ElementNode && n.Data == "meta" {
			var name, prop, content string
			for _, attr := range n.Attr {
				switch attr.Key {
				case "name":
					name = strings.ToLower(attr.Val)
				case "property":
					prop = strings.ToLower(attr.Val)
				case "content":
					content = attr.Val
				}
			}
			if (name == "description" || prop == "og:description") && content != "" && description == "" {
				description = strings.TrimSpace(content)
			}
		}

		// Continue traversing the tree
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			walk(c)
		}
	}

	walk(doc)

	return title, description
}

