func FetchURLPreview(ctx echo.Context) error {
	var req RequestBody
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
	}

	// Normalize URL: prepend http:// if scheme is missing.
	rawURL := req.URL
	if !strings.HasPrefix(rawURL, "http://") && !strings.HasPrefix(rawURL, "https://") {
		rawURL = "http://" + rawURL
	}

	// Validate URL format.
	if _, err := url.ParseRequestURI(rawURL); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid URL format"})
	}

	// Create HTTP client with 3 second timeout.
	client := &http.Client{Timeout: 3 * time.Second}

	// Perform GET request.
	resp, err := client.Get(rawURL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "non-200 status code"})
	}

	// Limit response body to 1 MB to avoid huge memory consumption.
	body, err := io.ReadAll(io.LimitReader(resp.Body, 1<<20))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to read response body"})
	}

	// Extract title and description from HTML.
	title, description := extractMeta(body)

	return ctx.JSON(http.StatusOK, Response{
		Title:       title,
		Description: description,
	})
