	req := new(PreviewRequest)
	if err := c.Bind(req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return c.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Prepare HTTP request
	client := &http.Client{Timeout: 5 * time.Second}
	httpReq, err := http.NewRequest(http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(httpReq)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return c.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return c.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription parses HTML and returns the <title> and
// <meta name="description"> content (if present).
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	// Extract <title>...</title>
	reTitle := regexp.MustCompile(`(?i)<title>([^<]+)</title>`)
	m := reTitle.FindSubmatch(htmlContent)
	var title string
	if m != nil {
		title = string(m[1])
	}

	// Extract <meta name="description" content="...">.
	// Support two common attribute orderings.
	reDesc1 := regexp.MustCompile(`(?i)<meta[^>]+name=["']description["'][^>]+content=["']([^"']+)"[']`)
	reDesc2 := regexp.MustCompile(`(?i)<meta[^>]+content=["']([^"']+)["'][^>]+name=["']description["']`)

	var description string
	if sub := reDesc1.FindSubmatch(htmlContent); sub != nil {
		description = string(sub[1])
	} else if sub := reDesc2.FindSubmatch(htmlContent); sub != nil {
		description = string(sub[1])
	}

	return title, description
}

func main() {
	// Echo instance
	e := echo.New()

	// Middleware (optional, but useful for logging/recovery)
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Register the preview handler
	e.POST("/preview", FetchURLPreview)

	// Start the server
	e.Logger.Fatal(e.Start(":1323"))
}

