// FetchURLPreview handles POST /preview
func FetchURLPreview(ctx echo.Context) error {
	var req URLRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	// Basic URL validation
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url is required"})
	}
	u, err := url.Parse(req.URL)
	if err != nil || u.Scheme == "" || u.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid URL format"})
	}

	// HTTP client with 3 seconds timeout
	client := &http.Client{Timeout: 3 * time.Second}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "unexpected status code: " + http.StatusText(resp.StatusCode)})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to read response body"})
	}

	html := string(body)
	title := extractTitle(html)
	description := extractMetaDescription(html)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitle tries to find <title>...</title> in the HTML
func extractTitle(html string) string {
	// pattern: <title>...</title> ignoring case and possible whitespace
	re := regexp.MustCompile(`(?i)<title[^>]*>(?P<title>[^<]+)</title>`)
	match := re.FindStringSubmatch(html)
	if len(match) > 1 {
		return match[1]
	}
	return ""
}

// extractMetaDescription looks for <meta name="description" content="..."> or
// <meta content="..." name="description">
func extractMetaDescription(html string) string {
	// order: name="description" then content=
	re1 := regexp.MustCompile(`(?i)<meta[^>]*name\s*=\s*["']description["'][^>]*content\s*=\s*["'](?P<desc>[^"']+)["']`)
	if m := re1.FindStringSubmatch(html); len(m) > 1 {
		return m[1]
	}

	// order: content= first then name="description"
	re2 := regexp.MustCompile(`(?i)<meta[^>]*content\s*=\s*["'](?P<desc>[^"']+)["'][^>]*name\s*=\s*["']description["']`)
	if m := re2.FindStringSubmatch(html); len(m) > 1 {
		return m[1]
	}

	return ""
}

func main() {
	e := echo.New()

	// Middleware
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Route
	e.POST("/preview", FetchURLPreview)

	// Start server
	e.Start(":8080")
}

