		Method: http.MethodGet,
		URL:    parsedURL,
		Header: map[string][]string{
			"User-Agent": {"Mozilla/5.0 (compatible; URLPreviewBot/1.0)"},
		},
	})
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(string(body))

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent string) (string, string) {
	title := ""
	description := ""

	// Convert to lowercase for case-insensitive matching
	lowerContent := strings.ToLower(htmlContent)

	// Extract title
	titleStart := strings.Index(lowerContent, "<title>")
	if titleStart == -1 {
		titleStart = strings.Index(lowerContent, "<title ")
	}
	if titleStart != -1 {
		titleTagEnd := strings.Index(lowerContent[titleStart:], ">")
		if titleTagEnd != -1 {
			titleStart = titleStart + titleTagEnd + 1
			titleEnd := strings.Index(lowerContent[titleStart:], "</title>")
			if titleEnd != -1 {
				title = strings.TrimSpace(htmlContent[titleStart : titleStart+titleEnd])
			}
		}
	}

	// Extract meta description
	descStart := strings.Index(lowerContent, `name="description"`)
	if descStart == -1 {
		descStart = strings.Index(lowerContent, `name='description'`)
	}
	if descStart != -1 {
		// Look for content attribute after name="description"
		contentStart := strings.Index(lowerContent[descStart:], "content=")
		if contentStart != -1 {
			descStart = descStart + contentStart + 8 // skip content="
			// Handle both double and single quotes
			quote := htmlContent[descStart-1]
			endQuote := strings.Index(htmlContent[descStart:], string(quote))
			if endQuote != -1 {
				description = strings.TrimSpace(htmlContent[descStart : descStart+endQuote])
			}
		}
	}

	return title, description
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

