// extractTitleAndDescription walks the HTML tree to extract the page title
// and the content of the meta description (or og:description as fallback).
func extractTitleAndDescription(n *html.Node) (title, description string) {
	var walk func(*html.Node)
	walk = func(node *html.Node) {
		if node.Type == html.ElementNode {
			switch node.Data {
			case "title":
				if node.FirstChild != nil && node.FirstChild.Type == html.TextNode {
					title = node.FirstChild.Data
				}
			case "meta":
				var name, prop, content string
				for _, attr := range node.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "property":
						prop = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if name == "description" && content != "" {
					description = content
				} else if prop == "og:description" && description == "" && content != "" {
					// Use Open Graph description if standard description is missing
					description = content
				}
			}
		}
		for child := node.FirstChild; child != nil; child = child.NextSibling {
			walk(child)
		}
	}
	walk(n)
	return title, description
}

func main() {
	e := echo.New()
	e.Use(middleware.Logger())
	e.Use(middleware.Recover())

	// Register the handler under POST /preview
	e.POST("/preview", FetchURLPreview)

