// FetchURLPreview handles POST requests to /preview.
// It receives a JSON body with a "url" field, fetches the page,
// extracts the <title> and meta description, and returns them as JSON.
func FetchURLPreview(ctx echo.Context) error {
	var req URLRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, URLPreviewResponse{Error: "invalid request body"})
	}

	// Basic validation
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, URLPreviewResponse{Error: "url is required"})
	}

	// Ensure URL has a scheme
	if !strings.HasPrefix(req.URL, "http://") && !strings.HasPrefix(req.URL, "https://") {
		req.URL = "https://" + req.URL
	}

	// Create HTTP client with 3‑second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Perform GET request
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, URLPreviewResponse{Error: fmt.Sprintf("failed to fetch URL: %v", err)})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, URLPreviewResponse{Error: fmt.Sprintf("received non‑200 status: %d", resp.StatusCode)})
	}

	// Read the response body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, URLPreviewResponse{Error: fmt.Sprintf("failed to read response: %v", err)})
	}

	// Parse HTML to extract title and description
	title, description, err := parseHTML(bytes.NewReader(body))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, URLPreviewResponse{Error: fmt.Sprintf("failed to parse HTML: %v", err)})
	}

	return ctx.JSON(http.StatusOK, URLPreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTML extracts the <title> and meta description from an HTML document.
// It uses the golang.org/x/net/html package.
func parseHTML(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var find func(*html.Node)
	find = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract <title> content
			if n.Data == "title" {
				for c := n.FirstChild; c != nil; c = c.NextSibling {
					if c.Type == html.TextNode {
						title = strings.TrimSpace(c.Data)
						break
					}
				}
			}

			// Extract <meta name="description"> or <meta property="og:description">
			if n.Data == "meta" {
				var name, prop, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						name = attr.Val
					}
					if attr.Key == "property" {
						prop = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if (name == "description" || prop == "og:description") && content != "" {
					description = strings.TrimSpace(content)
				}
			}
		}

		// Continue traversal unless both values are found
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			find(c)
			if title != "" && description != "" {
				return
			}
		}
	}

	find(doc)
	return title, description, nil
}

func main() {
